class TrieNode:
  root = None
  endOfWord = False
  children = [None] * 26

  def deleteWord(self, word):
    curr = self.root

    for i in range(len(word)):
      idx = ord(word[i]) - ord('a')

      if curr.children[idx] is None:
        return False

      curr = curr.children[idx]

    curr.endOfWord = False
    return True

class Trie:
  def __init__(self):
    self.root = TrieNode()

