class TrieNode {
 public:
  static TrieNode* root;
  bool isEndOfWord;
  TrieNode* children[26];
};

TrieNode* TrieNode::root = new TrieNode();

void deleteWord(string word) {
  TrieNode* curr = TrieNode::root;

  for (int i = 0; i < word.length(); i++) {
    int idx = word[i] - 'a';

    if (curr->children[idx] == nullptr) {
      return;
    }

    curr = curr->children[idx];
  }

  curr->isEndOfWord = false;
}

int main() {
  string word;
  cin >> word;
  deleteWord(word);
  return 0;
}

