class TrieNode {
  static root;
  isEndOfWord;
  children;

  constructor() {
    this.children = [];
  }

  deleteWord(word) {
    let curr = TrieNode.root;

    for (let i = 0; i < word.length; i++) {
      let idx = word.charCodeAt(i) - 'a'.charCodeAt(0);

      if (!curr.children[idx]) {
        return;
      }

      curr = curr.children[idx];
    }

    curr.isEndOfWord = false;
  }
}

